const { mode, query, content, namespace = 'default' } = $json;
if (!mode) return { error: 'mode required: search | store | delete' };
return { mode, query, content, namespace };

const { query, namespace, limit = 5 } = $json;
const ltmPath = '/home/timothy/Project/Arch-Mk2/ltm/store';
const fs = require('fs');
const path = require('path');
const results = [];
if (fs.existsSync(ltmPath)) {
  const files = fs.readdirSync(ltmPath).filter(f => f.endsWith('.jsonl'));
  for (const file of files) {
    const lines = fs.readFileSync(path.join(ltmPath, file), 'utf8').split('\n').filter(Boolean);
    for (const line of lines.slice(-100)) {
      try {
        const record = JSON.parse(line);
        const searchText = JSON.stringify(record).toLowerCase();
        if (query && searchText.includes(query.toLowerCase())) {
          results.push({ file, record });
          if (results.length >= limit) break;
        }
      } catch (e) {}
    }
    if (results.length >= limit) break;
  }
}
return { results, total: results.length, mode: 'search', query, searched_files: fs.existsSync(ltmPath) ? fs.readdirSync(ltmPath).filter(f => f.endsWith('.jsonl')) : [] };

const { content, namespace } = $json;
const ltmPath = '/home/timothy/Project/Arch-Mk2/ltm/store';
const fs = require('fs');
const path = require('path');
if (!fs.existsSync(ltmPath)) {
  fs.mkdirSync(ltmPath, { recursive: true });
}
const eventFile = path.join(ltmPath, 'events.jsonl');
const event = {
  id: `evt_${Date.now()}`,
  ts: new Date().toISOString(),
  type: 'n8n_vector_store',
  summary: typeof content === 'string' ? content : JSON.stringify(content).slice(0, 200),
  source: 'n8n-vector-memory',
  namespace
};
fs.appendFileSync(eventFile, JSON.stringify(event) + '\n');
return { stored: true, event_id: event.id, file: eventFile, mode: 'store' };
